import{_ as a,o as s,c as n,ak as e,al as l,am as t,an as p,ao as r,ap as d,aq as o,ar as h,as as g,at as b}from"./chunks/framework.DMc2NN9G.js";const V=JSON.parse('{"title":"Vibe Coding 是什么？","description":"","frontmatter":{},"headers":[],"relativePath":"AI/Vibe Coding/01.Vibe Coding 是什么.md","filePath":"AI/Vibe Coding/01.Vibe Coding 是什么.md","lastUpdated":0}'),c={name:"AI/Vibe Coding/01.Vibe Coding 是什么.md"};function k(u,i,m,A,C,I){return s(),n("div",null,[...i[0]||(i[0]=[e('<h1 id="vibe-coding-是什么" tabindex="-1">Vibe Coding 是什么？ <a class="header-anchor" href="#vibe-coding-是什么" aria-label="Permalink to “Vibe Coding 是什么？”">​</a></h1><h2 id="一、vibe-coding-概念" tabindex="-1">一、Vibe Coding 概念 <a class="header-anchor" href="#一、vibe-coding-概念" aria-label="Permalink to “一、Vibe Coding 概念”">​</a></h2><p>一句话解释 Vibe Coding，就是 <strong>用自然语言（人话）和 AI 聊天，让 AI 帮你生成代码、修改代码、优化代码的编程方式</strong>。</p><p>但是并不是简单的让 AI 写代码那么简单，是一种全新的开发思维与工作流程。</p><p>如果用比较正式的语言来说，Vibe Coding 是一种：</p><blockquote><p>以<strong>自然语言</strong>提示驱动<strong>大语言模型</strong>（LLM），让 AI 直接生成并迭代代码的意图驱动型开发模式。</p></blockquote><p>在这种模式下：</p><ul><li>你负责 &quot;想清楚要做什么&quot;（表达意图）</li><li>AI 负责 &quot;把它做出来&quot;（实现逻辑）</li><li>你们一起迭代优化（协作进化）</li></ul><p>不需要记住这么复杂的定义，只需要知道：</p><p><strong>Vibe Coding = 用人话和 AI 聊天 + AI 帮你写代码 + 一起迭代优化</strong></p><p><img src="'+l+`" alt="img"></p><h2 id="二、核心理念-意图驱动编程" tabindex="-1">二、核心理念：意图驱动编程 <a class="header-anchor" href="#二、核心理念-意图驱动编程" aria-label="Permalink to “二、核心理念：意图驱动编程”">​</a></h2><h3 id="_2-1-什么是意图驱动" tabindex="-1">2.1 什么是意图驱动？ <a class="header-anchor" href="#_2-1-什么是意图驱动" aria-label="Permalink to “2.1 什么是意图驱动？”">​</a></h3><p>==代码 VS 自然语言==</p><p>在传统编程؜中，你需要自己写代‍码来告诉计算机 “‎怎么做”（How）‎：</p><div class="language-python line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">python</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 传统方式：你要写出每一步怎么做</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">total </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 0</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">for</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> item </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">in</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> shopping_cart:</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    total </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> total </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">+</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> item.price</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">print</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(total)</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><p>而在 Vi؜be Coding‍ 中，你只需要告诉‎ AI &quot;要做什么‎&quot;（What）：</p><div class="language-text line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>你：帮我计算购物车里所有商品的总价</span></span>
<span class="line"><span>AI：好的，我来实现这个功能</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>看到区别了؜吗？你不需要关心循‍环怎么写、变量怎么‎命名，你只需要清楚‎地表达你的意图，A⁢I 就能帮你实现。</p><p>在 Vibe Coding 时代，最重要的 &quot;编程语言&quot; 不是 Python、JavaScript，<strong>而是你的母语</strong>！</p><p>这才是真正؜的中文编程，像我以‍前接触的什么易语言‎、Q 语言都弱爆了</p><p>以前学编程，你要记住：</p><ul><li>变量怎么定义</li><li>循环怎么写</li><li>函数怎么调用</li><li>各种语法规则</li></ul><p>现在，你只需要会说人话：</p><ul><li>我想做一个待办事项列表</li><li>这个按钮点击后跳转到首页</li><li>用户输入错误时显示红色提示</li></ul><p><strong>你的意图（自然语言）=&gt; 就是你的代码逻辑（代码）=&gt; 计算机知道该做什么。</strong></p><h3 id="_2-2-ai-是你的编程伙伴" tabindex="-1">2.2 AI 是你的编程伙伴 <a class="header-anchor" href="#_2-2-ai-是你的编程伙伴" aria-label="Permalink to “2.2 AI 是你的编程伙伴”">​</a></h3><p>很多人会把؜ AI 当做工具来‍使用，但是在 Vi‎be Coding‎ 中，AI 不是工⁢具，而是你的编程伙伴：</p><ul><li>你是产品经理：负责想清楚要做什么</li><li>AI 是工程师：负责把它实现出来</li><li>你们是团队：一起讨论、迭代、优化</li></ul><p>这种协作模؜式，让编程从 &quot;孤‍独的战斗&quot; 变成了‎ &quot;愉快的对话&quot;。</p><h2 id="三、传统编程思维和-vibe-coding-思维" tabindex="-1">三、传统编程思维和 Vibe Coding 思维 <a class="header-anchor" href="#三、传统编程思维和-vibe-coding-思维" aria-label="Permalink to “三、传统编程思维和 Vibe Coding 思维”">​</a></h2><p>让我用一个表格，帮你理解这两种思维的区别：</p><table tabindex="0"><thead><tr><th>维度</th><th>传统编程</th><th>Vibe Coding</th></tr></thead><tbody><tr><td><strong>核心能力</strong></td><td>写代码（背语法）</td><td>表达需求（说人话）</td></tr><tr><td><strong>学习重点</strong></td><td>编程语言、算法、数据结构</td><td>产品思维、需求表达、迭代优化</td></tr><tr><td><strong>工作方式</strong></td><td>自己从零开始写</td><td>和 AI 对话生成</td></tr><tr><td><strong>出问题时</strong></td><td>自己调试、查文档、搜索</td><td>把错误告诉 AI，让它修复</td></tr><tr><td><strong>优化代码</strong></td><td>重构、优化算法</td><td>告诉 AI 优化方向</td></tr><tr><td><strong>学习曲线</strong></td><td>陡峭（需要几个月到几年）</td><td>平缓（可以几天上手）</td></tr><tr><td><strong>适合人群</strong></td><td>理工科背景、逻辑思维强</td><td>任何会表达需求的人</td></tr></tbody></table><p>举个例子，比如你想做一个天气查询应用。</p><p>如果用传统编程思维：</p><ol><li>先学一门编程语言（比如 JavaScript）</li><li>学习如何搭建网页</li><li>学习如何调用天气 API</li><li>学习如何处理 JSON 数据</li><li>学习如何设计界面</li><li>花几周时间一点点写代码</li></ol><p>如果用 Vibe Coding 思维：</p><ol><li>对 AI 说：&quot;帮我做一个天气查询网页，可以输入城市名，显示温度和天气状况&quot;</li><li>AI 生成初版代码</li><li>你看到效果后说：&quot;再加个搜索历史功能&quot;</li><li>AI 帮你加上</li><li>你说：&quot;界面改成蓝色调，更清爽一些&quot;</li><li>AI 帮你调整</li><li>半小时搞定！</li></ol><p><img src="`+t+'" alt="img"></p><p>看到区别了吗？传统编程关注 “怎么做”，Vibe Coding 关注 “做什么”。<strong>把需求讲清楚很重要。</strong></p><h2 id="四、一个真实的例子" tabindex="-1">四、一个真实的例子 <a class="header-anchor" href="#四、一个真实的例子" aria-label="Permalink to “四、一个真实的例子”">​</a></h2><p>说了这么多؜理论，让我给你看一‍个真实的 Vibe‎ Coding‎ 案例。</p><h3 id="背景" tabindex="-1">背景 <a class="header-anchor" href="#背景" aria-label="Permalink to “背景”">​</a></h3><p>我有个老师朋؜友，她每周都要把学生的‍考勤、作业完成情况发给‎家长。以前她都是一条一‎条地把学生的情况编辑成⁢文字，每次都要花一两个小时。</p><p>于是她问我能不能做个工具，输入学生信息后自动生成周报信息。</p><h3 id="用-vibe-coding-实现" tabindex="-1">用 Vibe Coding 实现 <a class="header-anchor" href="#用-vibe-coding-实现" aria-label="Permalink to “用 Vibe Coding 实现”">​</a></h3><p>我打开 Cu؜rsor（一个主流的 ‍AI 代码编辑器），进‎入一个空的目录（用来装‎生成的项目代码），然后⁢准备和 AI 对话：</p><p><img src="'+p+`" alt="img"></p><p>第 1 轮对话：</p><div class="language-markdown line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">markdown</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">要求：</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">1.</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> 可以输入学生姓名、考勤天数、作业完成数</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">2.</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> 点击生成按钮后，自动生成一段周报文字</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">3.</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> 可以一键复制到剪贴板</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><p>AI 立刻给我生成了一个初版页面，包含表单输入框和按钮。</p><p><img src="`+r+`" alt="img"></p><p>第 2 轮对话：</p><div class="language-dust line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">dust</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>我：周报的格式改成这样：</span></span>
<span class="line"><span>&quot;【学生周报】{姓名}同学本周表现：出勤{考勤}天，完成作业{作业}份。{评价}&quot;</span></span>
<span class="line"><span>其中评价根据完成情况自动生成</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p>AI 修改了代码，加上了智能评价功能（虽然没有特别智能）。</p><p><img src="`+d+'" alt="img"></p><p>第 3 轮对话：</p><div class="language-undefined line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">undefined</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>我：界面太简陋了，改成清新的绿色调，加点圆角和阴影</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>AI 美化了界面。</p><p><img src="'+o+'" alt="img"></p><p>第 4 轮对话：</p><div class="language-undefined line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">undefined</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>我：加个历史记录功能，可以看到之前生成的周报</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>AI 加上了历史记录。</p><p><img src="'+h+'" alt="img"></p><p>从开始到完成，一共花了不到 <strong>10 分钟</strong>。我朋友现在每周用这个工具，省下来的时间够陪我玩一把狼人杀了。</p><p>注意我在这个过程中做了什么：</p><ul><li>我没有写一行代码（全是 AI 写的）</li><li>我只是清楚地表达了需求</li><li>我通过多轮对话不断优化</li><li>我关注的是功能和效果，不是实现细节</li></ul><p>这就是 Vibe Coding 的魔力！</p><h2 id="五、vibe-coding-能做什么" tabindex="-1">五、Vibe Coding 能做什么？ <a class="header-anchor" href="#五、vibe-coding-能做什么" aria-label="Permalink to “五、Vibe Coding 能做什么？”">​</a></h2><p>你可能会想؜：Vibe Cod‍ing 听起来很酷‎，但它到底能做哪些‎事情呢？</p><p>答案是：<strong>几乎所有你能想到的软件开发，它都能做！</strong></p><p>比如下面这些实用的软件：</p><p>1）网页应؜用：个人作品集网站‍、在线工具（待办事‎项、记账、笔记等）‎、企业官网、博客系⁢统、在线商城</p><p>2）小程序 / App</p><p>3）AI ؜应用：聊天机器人、‍智能写作助手、图片‎生成工具、语音识别‎应用</p><p>4）数据处理工具：数据可视化、自动化报表、表格处理工具</p><p>5）自动化脚本：批量文件处理、爬虫工具、自动化测试</p><p>6）辅助工؜具：展示 PPT ‍的网页、原型图和演‎示网站、架构图和流‎程图、动画演示网站</p><h2 id="六、为什么现在是学编程的最好时代" tabindex="-1">六、为什么现在是学编程的最好时代？ <a class="header-anchor" href="#六、为什么现在是学编程的最好时代" aria-label="Permalink to “六、为什么现在是学编程的最好时代？”">​</a></h2><p>如果你曾经被编程劝退过，那么我要告诉你一个好消息：<strong>今天，是人类历史上学习编程最容易的时刻！</strong></p><p><strong>门槛从未如此之低</strong></p><p>以前学编程，你要花؜少说几个月学习基础知识、面对无数的‍报错和调试。现在学 Vibe Co‎ding，你只需要会说人话、会表达‎需求，几天就能上手，像聊天一样编程⁢，AI 帮你解决大部分问题。</p><p><strong>从想法到产品的距离更短</strong></p><p>以前，你有个؜好点子，但实现它可能需‍要学习几个月编程，再花‎几周甚至几个月开发，或‎者招一个程序员，最后可⁢能只能放弃这个想法。</p><p>现在，用 ؜Vibe Codi‍ng，今天想到一个‎点子，今天就能做出‎来，甚至可以直接部⁢署上线，成本接近于零。JnD5W5+bNqzzsYZMNcEPgWoqILTzMMmiaUXM6LMblR4=</p><p><strong>创造力比技术更重要</strong></p><p>在 AI 时代؜，最重要的不再是 &quot;会写代‍码&quot;，而是会想创意（创造力‎）、会表达需求（沟通能力）‎、会迭代优化（产品思维）。⁢这些能力，任何人都可以培养。</p><p><strong>终身学习成为可能</strong></p><p>以前，编程技术更؜新太快，学了可能很快就过时。现‍在，有了 AI 助手，新技术出‎来 AI 就已经学会了，你只需‎要告诉 AI 用新技术实现，可⁢以把精力放在创意和产品上。</p><h2 id="七、3-大-vibe-coding-误区" tabindex="-1">七、3 大 Vibe Coding 误区 <a class="header-anchor" href="#七、3-大-vibe-coding-误区" aria-label="Permalink to “七、3 大 Vibe Coding 误区”">​</a></h2><p>在开始学习؜ Vibe Codi‍ng 之前，我必须帮‎你破除 3 个常见‎的误区。很多同学就是因⁢为这些误区，迟迟不敢开始。n3Ufv6MFCK730p35U8TbJ2m+lV0ubqAfk2PylJyK0iM=</p><h3 id="_7-1-误区-1-vibe-coding-是不是在作弊" tabindex="-1">7.1 误区 1 =&gt; Vibe Coding 是不是在作弊？ <a class="header-anchor" href="#_7-1-误区-1-vibe-coding-是不是在作弊" aria-label="Permalink to “7.1 误区 1 =&gt; Vibe Coding 是不是在作弊？”">​</a></h3><p>当然不是！</p><p>有些传统程序员会说：用 AI 写代码，那不就是不会编程吗？</p><p>那让我们想一想：</p><ul><li>100 年前，会心算的人觉得用计算器是作弊</li><li>30 年前，会手写代码的人觉得用 IDE 是作弊</li><li>今天，会手写代码的人觉得用 AI 是作弊</li></ul><p><strong>工具的进步，不是作弊，而是效率的提升。</strong></p><p>你用 AI؜ 写代码，就像设计‍师用 Photos‎hop、建筑师用 ‎CAD 一样，是正⁢常的生产力工具。</p><p>关键不是你؜怎么实现的，而是你‍能不能把东西做出来‎，能不能解决问题。</p><p>==AI 是生产工具，是将你能力放大的放大镜🔎==</p><h3 id="_7-2-误区-2-vibe-coding-会让我失去学习能力吗" tabindex="-1">7.2 误区 2 =&gt; Vibe Coding 会让我失去学习能力吗？ <a class="header-anchor" href="#_7-2-误区-2-vibe-coding-会让我失去学习能力吗" aria-label="Permalink to “7.2 误区 2 =&gt; Vibe Coding 会让我失去学习能力吗？”">​</a></h3><p>有人担心：؜如果总是让 AI ‍写代码，我不就什么‎都学不到了吗？</p><p>恰恰相反！Vibe Coding 是最好的学习方式：</p><ul><li>AI 生成代码后，你可以阅读理解</li><li>你不懂的地方，可以问 AI 解释</li><li>你可以尝试修改代码，看看效果</li><li>你可以边做项目边学习</li></ul><p>==在实战中学习，远比啃书本效率高得多！==</p><h3 id="_7-3-误区-3-vibe-coding-只能做简单的玩具项目吗" tabindex="-1">7.3 误区 3 =&gt; Vibe Coding 只能做简单的玩具项目吗？ <a class="header-anchor" href="#_7-3-误区-3-vibe-coding-只能做简单的玩具项目吗" aria-label="Permalink to “7.3 误区 3 =&gt; Vibe Coding 只能做简单的玩具项目吗？”">​</a></h3><p>当然不是！复杂项目一样能做！</p><p>有人觉得 AI 只能写些简单代码，复杂项目还得靠程序员。</p><p>但实际上，如今的 AI 已经非常强大了：</p><ul><li>可以处理几万行代码的项目</li><li>可以理解复杂的业务逻辑</li><li>可以使用各种框架和技术栈</li><li>可以帮你调试复杂的 bug</li></ul><p>==关键的限制不是 AI 的能力，而是你的需求表达和迭代能力。==</p><h2 id="八、vibe-coding-的问题" tabindex="-1">八、Vibe Coding 的问题 <a class="header-anchor" href="#八、vibe-coding-的问题" aria-label="Permalink to “八、Vibe Coding 的问题”">​</a></h2><p>虽然 Vibe؜ Coding 很强大，但‍我也要诚实地告诉你，它目前‎还存在一些局限性。了解这些‎问题，能帮你更理性地使用 ⁢Vibe Coding。</p><h3 id="_8-1-界面同质化" tabindex="-1">8.1 界面同质化 <a class="header-anchor" href="#_8-1-界面同质化" aria-label="Permalink to “8.1 界面同质化”">​</a></h3><p>你可能会发现，很多؜用 AI 生成的网站界面都长得很像，‍特别是颜色 —— 经常是淡紫色或蓝紫渐‎变色。这是因为 AI 的训练数据中‎，这类设计（或者引用的样式代码）比较⁢常见，所以它会倾向于生成类似的风格。</p><p><img src="'+g+'" alt="img"></p><p>如果你想要؜独特的设计，需要在‍提示词中明确说明颜‎色、风格、参考案例‎，或者提供设计稿让 A⁢I 参考。</p><p>e.g.</p><ul><li>参考 XXX 网站</li><li>强制 AI 使用 XXX 主题或者颜色</li></ul><h3 id="_8-2-代码不可控的风险" tabindex="-1">8.2 代码不可控的风险 <a class="header-anchor" href="#_8-2-代码不可控的风险" aria-label="Permalink to “8.2 代码不可控的风险”">​</a></h3><p>还有个更麻烦的问题，就是 AI 生成的代码不可控。AI 目前更多地还是用来生成小项目，如果你在有点儿体量的代码库下使用 AI，出 Bug 时，就很可能出现调试困难的 <strong>死局</strong> —— 你既看不懂 AI 生成的代码，又舍不得放弃这些代码。之前在 AI 社群里，就看到有开发者吐槽同事用 AI 把项目改崩了</p><p><img src="'+b+'" alt="img"></p><p>这就是为什么我建议：</p><ul><li>尽量让 AI 生成简单、清晰的代码</li><li>每次生成代码后都要测试</li><li>遇到问题及时回滚，不要一条路走到黑</li><li>有条件的话，学习一些基础的编程知识</li></ul><h3 id="_8-3-技能退化的风险" tabindex="-1">8.3 技能退化的风险 <a class="header-anchor" href="#_8-3-技能退化的风险" aria-label="Permalink to “8.3 技能退化的风险”">​</a></h3><p>长期使用 ؜Vibe Codi‍ng，可能会让你失‎去一些基本的编‎程技能。就像长期用计算⁢器，心算能力会下降一样。</p><p>所以我建议有编程基础的程序员朋友们：</p><ul><li>不要完全依赖 AI，保持一定的手写代码能力</li><li>尝试理解 AI 生成的代码，而不是盲目使用</li><li>定期做一些不用 AI 的练习</li><li>把 AI 当助手，而不是替代品</li></ul><p>但说实话，这个؜问题对于零基础的朋友来说完‍全不是问题，因为你本来就没‎有编程技能可以退化，反而可‎以在 Vibe Codin⁢g 的过程中学到很多编程知识。</p>',129)])])}const f=a(c,[["render",k]]);export{V as __pageData,f as default};
